local cjson = require "cjson"

local function parse_xml_safe(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML content"
    end
    
    local patterns_to_check = {
        "<!ENTITY",
        "<!DOCTYPE",
        "SYSTEM",
        "PUBLIC"
    }
    
    for _, pattern in ipairs(patterns_to_check) do
        if string.find(xml_string, pattern, 1, true) then
            return nil, "XML contains potentially dangerous constructs: " .. pattern
        end
    end
    
    local entity_refs = {}
    for entity in string.gmatch(xml_string, "&([%w_]+);") do
        if entity ~= "lt" and entity ~= "gt" and entity ~= "amp" and 
           entity ~= "quot" and entity ~= "apos" then
            return nil, "Disallowed entity reference: &" .. entity .. ";"
        end
    end
    
    return xml_string
end

local function decode_entities(text)
    if not text then return text end
    
    local entities = {
        ["&lt;"] = "<",
        ["&gt;"] = ">",
        ["&amp;"] = "&",
        ["&quot;"] = '"',
        ["&apos;"] = "'"
    }
    
    for entity, char in pairs(entities) do
        text = string.gsub(text, entity, char)
    end
    
    return text
end

local function parse_xml_to_table(xml_string)
    local stack = {}
    local top = {name = "root", children = {}, attrs = {}}
    table.insert(stack, top)
    
    local i = 1
    while i <= #xml_string do
        local tag_start, tag_end = string.find(xml_string, "<[^>]+>", i)
        
        if not tag_start then
            local text = string.sub(xml_string, i)
            text = string.match(text, "^%s*(.-)%s*$")
            if text and text ~= "" then
                local current = stack[#stack]
                table.insert(current.children, {type = "text", value = decode_entities(text)})
            end
            break
        end
        
        if tag_start > i then
            local text = string.sub(xml_string, i, tag_start - 1)
            text = string.match(text, "^%s*(.-)%s*$")
            if text and text ~= "" then
                local current = stack[#stack]
                table.insert(current.children, {type = "text", value = decode_entities(text)})
            end
        end
        
        local tag = string.sub(xml_string, tag_start, tag_end)
        
        if string.sub(tag, 1, 4) == "<!--" then
            i = tag_end + 1
        elseif string.sub(tag, 1, 2) == "<?" then
            i = tag_end + 1
        elseif string.sub(tag, 1, 2) == "</" then
            local tag_name = string.match(tag, "</([%w:_%-]+)")
            if tag_name then
                table.remove(stack)
            end
            i = tag_end + 1
        else
            local is_self_closing = string.sub(tag, -2, -1) == "/>"
            local tag_content = string.sub(tag, 2, is_self_closing and -3 or -2)
            
            local tag_name = string.match(tag_content, "^([%w:_%-]+)")
            local attrs = {}
            
            for attr_name, attr_value in string.gmatch(tag_content, '([%w:_%-]+)%s*=%s*["\']([^"\']*)["\']') do
                attrs[attr_name] = decode_entities(attr_value)
            end
            
            local node = {
                name = tag_name,
                attrs = attrs,
                children = {}
            }
            
            local current = stack[#stack]
            table.insert(current.children, node)
            
            if not is_self_closing then
                table.insert(stack, node)
            end
            
            i = tag_end + 1
        end
    end
    
    return top
end

local function xml_to_lua_table(node)
    if not node then return nil end
    
    local result = {}
    
    if node.attrs then
        for k, v in pairs(node.attrs) do
            result["@" .. k] = v
        end
    end
    
    if node.children then
        for _, child in ipairs(node.children) do
            if child.type == "text" then
                if not result["#text"] then
                    result["#text"] = child.value
                else
                    result["#text"] = result["#text"] .. child.value
                end
            elseif child.name then
                local child_table = xml_to_lua_table(child)
                
                if not result[child.name] then
                    result[child.name] = child_table
                else
                    if type(result[child.name]) ~= "table" or result[child.name][1] == nil then
                        result[child.name] = {result[child.name]}
                    end
                    table.insert(result[child.name], child_table)
                end
            end
        end
    end
    
    return result
end

local function extract_soap_body(parsed_xml)
    if not parsed_xml or not parsed_xml.children then
        return nil, "Invalid XML structure"
    end
    
    for _, child in ipairs(parsed_xml.children) do
        if child.name and (string.lower(child.name) == "envelope" or 
           string.match(child.name, "[Ee]nvelope$")) then
            
            for _, envelope_child in ipairs(child.children) do
                if envelope_child.name and (string.lower(envelope_child.name) == "body" or 
                   string.match(envelope_child.name, "[Bb]ody$")) then
                    return xml_to_lua_table(envelope_child)
                end
            end
        end
    end
    
    return xml_to_lua_table(parsed_xml)
end

